import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"二天一流","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/二天一流.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/二天一流.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/二天一流.md"};function d(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"二天一流",tabindex:"-1"},[n("二天一流 "),r("a",{class:"header-anchor",href:"#二天一流","aria-label":'Permalink to "二天一流"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="二天一流-1" tabindex="-1">二天一流 <a class="header-anchor" href="#二天一流-1" aria-label="Permalink to &quot;二天一流&quot;">​</a></h1><p>下属技艺无需按顺序购买</p><p>双刀流<br> D+500</p><p>购买前提：阿修罗—1，无双剑士—1</p><p>宫本武藏所用剑技，以右手太刀、左手小太刀为标配，遵循二天一流 “对立统一” 的核心，长刀主攻劈砍、突刺，负责破开防御、制造致命伤，短刀主防格挡、牵制，同时兼顾近身点刺、封锁对手动作，双刀配合无丝毫滞涩，抬手间即可完成攻防转换。</p><p>当双手持有刀剑类武器进行攻击时，你可以将未加入攻击的那把武器的一半基础属性与所有特性加入本次攻击中，若当前主要使用的武器与上次使用的武器不同，则本次攻击额外具有【C先制】。</p><p>二天一流</p><p>B+3000<br> 购买前提：阿修罗—2<br> 可由双刀流差价升级而来</p><p>身体通过踏步位移和用腰挥剑产生强劲的力道，<br> 手臂则从极度放松状态，瞬间以肩关节为轴，运用臂力腕力大动作挥砍，为刀施加速度，<br> 手掌，只以食指勾握刀柄，以拇指侧压刀鎺，其余三指则伸直蓄力，在挥舞同时以食指为支撑点，其余三指握紧刀柄，对刀柄施加一个极强的握力，在由刀柄放大至刀身上，<br> 如此，便能一口气斩开敌人的身体。</p><p>当双手持有刀剑类武器进行攻击时，你可以将未加入攻击的那把武器的一半基础属性与所有特性加入本次攻击中，若当前主要使用的武器与上次使用的武器不同，则本次攻击额外具有【A先制】。<br> 在挥舞时的高超技巧令这次刀剑的攻击可以无视敌人全部的天生防御和盔甲防御，这是一个接触攻击效果。</p><p>意识斩<br> B+2000</p><p>购买前提：无双剑士—2<br> 书法之真谛在于意境，从楷书到行书，再到草书，大繁至简，方能极境至臻，<br> 而剑法与书法同理，均是手腕之力与胸中之气绘成，境界相同，<br> 以笔墨在白纸上行草书，再到以指代笔行书，再到在任何可称之为平面之处，以意志代替笔墨挥毫，<br> 最后在仰望天空时，在空中行狂草，<br> 在剑道中的草书之上的，是宫本武藏晚年才创造的无刀之境。</p><p>以自由动作消耗5点意志力使用，对触及范围内的某一单位使用该技艺，面对意识斩的敌人需要以【感知+洞察+察言观色+武学掌握】对抗你的【决心+武技+刀剑类专业+武学掌握】，若失败，则其会感受到被刀剑斩开的真实触感，从而露出破绽，其会在一轮内陷入无支线级别措手不及状态，并且在意志豁免上受到【劣化2】影响，这是一个B级创伤来源的效果，同时失去3点格挡防御，且目标失败后的一轮内进行招架时，所能抵挡的伤害减少一半。这是一个类虚招效果。<br> 面对构造体时，意识斩自动失效。<br> 每在武技技能上具有1附加成功，就减少1点该技艺的意志力消耗。</p><p>————额外支付B+2000将该技艺升级至A级</p><p>在使用该技艺时，视作触及范围扩大120M，且可以对触及范围内的全部单位使用该技艺，<br> 在对抗失败时，改为对方在意志豁免上受到【劣化3】影响，这是一个A级创伤来源的效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
